const input = $input.first().json;
const body = input.body ?? input;
const event = body.event ?? body.type ?? body.action ?? 'message';
const nestedMessage = body.message ?? body.data?.message ?? body.payload?.message ?? {};
const contact = body.contact ?? body.data?.contact ?? body.payload?.contact ?? {};
const text = String(
  body.text ??
  body.content ??
  body.messageText ??
  nestedMessage.text ??
  nestedMessage.body ??
  nestedMessage.content ??
  body.data?.text ??
  body.payload?.text ??
  ''
);
const phone = String(
  body.phone ??
  body.from ??
  body.customerPhone ??
  contact.phone ??
  contact.whatsapp ??
  contact.wa_id ??
  nestedMessage.from ??
  ''
);
const customerName = String(
  body.customerName ??
  body.name ??
  contact.name ??
  contact.fullName ??
  contact.profile?.name ??
  'Cliente WhatsApp'
);
const lower = text.toLowerCase();
const isCustom = lower.includes('personalizada') || lower.includes('personaliza') || lower.includes('cotizar');
const color = text.match(/color:\s*([^.,\n]+)/i)?.[1]?.trim();
const size = text.match(/talla:\s*([^.,\n]+)/i)?.[1]?.trim();
const quantity = Number(text.match(/(\d+)\s*prenda/i)?.[1] ?? body.quantity ?? 1);
const total = Number(text.match(/bs\s*(\d+(?:[.,]\d+)?)/i)?.[1]?.replace(',', '.') ?? body.total ?? 0);

return [{
  json: {
    waflowEvent: event,
    rawText: text,
    customerName,
    customerPhone: phone,
    messageType: nestedMessage.type ?? body.messageType ?? 'text',
    receivedAt: new Date().toISOString(),
    action: 'create_order',
    type: isCustom ? 'custom' : 'catalog',
    product: isCustom ? 'Polera personalizada' : 'Pedido catalogo',
    color,
    size,
    quantity,
    total,
    notes: text,
    designDetails: isCustom ? text : undefined,
    quoteOption: text.match(/(solo\s+[^.\n]+|frente\s+[^.\n]+|espalda\s+[^.\n]+)/i)?.[1]?.trim(),
    source: 'waflow'
  }
}];
